using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    /// <summary>
    /// Creates an in-memory SchoolContext. Use the same dbName to share data across context instances.
    /// </summary>
    public static SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    /// <summary>
    /// Drains the static NotificationService queue to prevent cross-test interference.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    /// <summary>
    /// Seeds multiple students into the context and saves.
    /// </summary>
    public static List<Student> SeedStudents(SchoolContext context)
    {
        var students = new List<Student>
        {
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) }
        };
        context.Students.AddRange(students);
        context.SaveChanges();
        return students;
    }

    /// <summary>
    /// Seeds an instructor and a department. Returns the department.
    /// </summary>
    public static (Department department, Instructor instructor) SeedDepartmentWithInstructor(SchoolContext context)
    {
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = new DateTime(2015, 3, 11),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var department = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructor.ID
        };
        context.Departments.Add(department);
        context.SaveChanges();

        return (department, instructor);
    }

    /// <summary>
    /// Seeds courses along with a department and instructor.
    /// </summary>
    public static List<Course> SeedCoursesWithDepartment(SchoolContext context)
    {
        var (dept, _) = SeedDepartmentWithInstructor(context);
        var courses = new List<Course>
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
        };
        context.Courses.AddRange(courses);
        context.SaveChanges();
        return courses;
    }
}

