using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Alexander",
            FirstMidName = "Carson"
        };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.AreEqual("Alexander, Carson", fullName);
    }

    [TestMethod]
    public void FullName_Instructor_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi"
        };

        // Act
        var fullName = instructor.FullName;

        // Assert
        Assert.AreEqual("Fakhouri, Fadi", fullName);
    }

    [TestMethod]
    [DataRow("Smith", "John", "Smith, John")]
    [DataRow("O'Brien", "Pat", "O'Brien, Pat")]
    [DataRow("", "", ", ")]
    public void FullName_VariousNames_ReturnsExpectedFormat(string lastName, string firstName, string expected)
    {
        // Arrange
        var student = new Student
        {
            LastName = lastName,
            FirstMidName = firstName
        };

        // Act & Assert
        Assert.AreEqual(expected, student.FullName);
    }
}

