using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_WithEmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_SinglePage_ContainsAllItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        CollectionAssert.AreEqual(new[] { 1, 2, 3, 4, 5 }, result);
    }

    [TestMethod]
    public void Create_MultiplePagesFirstPage_ReturnsCorrectSlice()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        CollectionAssert.AreEqual(Enumerable.Range(1, 10).ToList(), result);
    }

    [TestMethod]
    public void Create_MultiplePagesSecondPage_ReturnsCorrectSlice()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(2, result.PageIndex);
        CollectionAssert.AreEqual(Enumerable.Range(11, 10).ToList(), result);
    }

    [TestMethod]
    public void Create_MultiplePagesLastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(3, result.PageIndex);
        CollectionAssert.AreEqual(Enumerable.Range(21, 5).ToList(), result);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnFirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_WithPartialLastPage()
    {
        // Arrange — 11 items with page size 5 = 3 pages (5+5+1)
        var source = Enumerable.Range(1, 11).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_WithExactFit()
    {
        // Arrange — 10 items with page size 5 = 2 pages
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain the static queue to prevent cross-test interference
        TestHelpers.DrainNotificationQueue();
        _service = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesNotificationInQueue()
    {
        // Act
        _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.AreEqual("New Student 'Carson Alexander' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Course", "101", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Instructor", "3", "Kim Abercrombie", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
