    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_ReturnsEnrollmentDateGroups()
    {
        // Arrange
        _context.Students.AddRange(
            new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = new DateTime(2021, 9, 1) }
        );
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        // Verify group counts
        var group2020 = model.Single(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
        Assert.AreEqual(2, group2020.StudentCount);

        var group2021 = model.Single(g => g.EnrollmentDate == new DateTime(2021, 9, 1));
        Assert.AreEqual(1, group2021.StudentCount);
    }

