using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    private Instructor SeedInstructorWithCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1050 }
            },
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        return instructor;
    }

    // --- Index ---

    [TestMethod]
    public void Index_NoSelectedInstructor_ReturnsAllInstructors()
    {
        // Arrange
        SeedInstructorWithCourses();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Instructors.Count());
        Assert.IsNull(model.Courses);
    }

    [TestMethod]
    public void Index_WithSelectedInstructor_ShowsInstructorCourses()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();

        // Act
        var result = _controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    [TestMethod]
    public void Index_WithSelectedCourse_ShowsEnrollments()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();

        // Add enrollment
        var student = new Student { LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Now };
        _context.Students.Add(student);
        _context.SaveChanges();
        _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = student.ID, Grade = Grade.A });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(instructor.ID, 1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Enrollments);
        Assert.AreEqual(1, model.Enrollments.Count());
    }

    // --- Details ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsInstructorView()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();

        // Act
        var result = _controller.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Fakhouri", model.LastName);
        Assert.AreEqual("Fadi", model.FirstMidName);
    }

    [TestMethod]
    public void Details_NotFoundId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithCoursesInViewBag()
    {
        // Arrange
        SeedInstructorWithCourses();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<Instructor>(result.Model);
        Assert.IsNotNull(result.ViewData["Courses"]);
        var courses = result.ViewData["Courses"] as List<AssignedCourseData>;
        Assert.IsNotNull(courses);
        Assert.AreEqual(2, courses.Count); // 2 courses seeded
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidInstructor_SavesAndRedirects()
    {
        // Arrange
        SeedInstructorWithCourses();
        var newInstructor = new Instructor
        {
            LastName = "NewLast",
            FirstMidName = "NewFirst",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(newInstructor, null);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "NewLast");
        Assert.IsNotNull(saved);
        Assert.AreEqual("NewFirst", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
    {
        // Arrange
        SeedInstructorWithCourses();
        var newInstructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(newInstructor, new[] { "1050", "4022" });

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);

        var saved = _context.Instructors
            .Include(i => i.CourseAssignments)
            .FirstOrDefault(i => i.LastName == "WithCourses");
        Assert.IsNotNull(saved);
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithCourses()
    {
        // Arrange
        SeedInstructorWithCourses();
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.ViewData["Courses"]);
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null as int?);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsInstructorView()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();

        // Act
        var result = _controller.Edit(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Fakhouri", model.LastName);
        Assert.IsNotNull(result.ViewData["Courses"]);
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsInstructorView()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();

        // Act
        var result = _controller.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Fakhouri", model.LastName);
    }

    [TestMethod]
    public void Delete_Get_NotFoundId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed ---

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange
        var instructor = SeedInstructorWithCourses();
        var instructorId = instructor.ID;

        // Act
        var result = _controller.DeleteConfirmed(instructorId);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.IsNull(_context.Instructors.Find(instructorId));
    }

    [TestMethod]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
        // Arrange — create an instructor who is an administrator of a department
        var instructor = SeedInstructorWithCourses();
        var dept = _context.Departments.First();
        dept.InstructorID = instructor.ID;
        _context.SaveChanges();

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert — the department's InstructorID should now be null
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

